from collections import Counter

class Solution:
    def takeCharacters(self, s, k):
        n = len(s)
        total = Counter(s)
        if total.get('a', 0) < k or total.get('b', 0) < k or total.get('c', 0) < k:
            return -1
        for m in range(0, n + 1):
            found = False
            for left_take in range(0, m + 1):
                right_take = m - left_take
                if left_take + right_take > n:
                    continue
                taken = s[:left_take] + (s[n - right_take:] if right_take > 0 else '')
                c = Counter(taken)
                if c.get('a', 0) >= k and c.get('b', 0) >= k and c.get('c', 0) >= k:
                    found = True
                    break
            if found:
                return m
        return -1

