from collections import Counter

class Solution:
    def takeCharacters(self, s, k):
        total = Counter(s)
        for c in 'abc':
            if total.get(c, 0) < k:
                return -1
        allowed = {c: total.get(c, 0) - k for c in 'abc'}
        n = len(s)
        left = 0
        cnt = {'a': 0, 'b': 0, 'c': 0}
        best = 0
        for right in range(n):
            cnt[s[right]] += 1
            while cnt[s[right]] > allowed[s[right]]:
                cnt[s[left]] -= 1
                left += 1
            best = max(best, right - left + 1)
        return n - best

